const body = $json.body || $json;
const text = body.text || body.description || '';
const source = body.source || body.channel || 'unknown';
const videoTitle = body.videoTitle || body.title || 'Untitled video';
const lines = text.split(/\n+/).map(l => l.trim()).filter(Boolean);
const items = [];
for (const line of lines) {
  const url = (line.match(/https?:\/\/\S+/) || [''])[0];
  const cleaned = line.replace(url, '').replace(/^[-•*\d:.\s]+/, '').trim();
  if (!cleaned || cleaned.length < 3) continue;
  if (url || /^[A-Za-z0-9].{2,80}$/.test(cleaned)) {
    items.push({
      product_name: cleaned.slice(0, 120),
      source,
      video_title: videoTitle,
      source_url: body.url || '',
      raw_line: line,
      buy_url: url,
      status: url ? 'Researching' : 'Needs Link',
      created_at: new Date().toISOString()
    });
  }
}
return items.slice(0, 300).map(item => ({ json: item }));

function category(name){
 const t = name.toLowerCase();
 if (/(saw|drill|jig|tester|sprayer|cutter|welding|level|jack|clamp|bender|grinder|nailer|rivet|pump|heater|shear)/.test(t)) return 'Pro Tools';
 if (/(sofa|bed|lamp|chair|table|litter|dishwasher|vacuum|cabinet|rack|ottoman|furniture|home)/.test(t)) return 'Smart Home & Furniture';
 if (/(camera|printer|recorder|nas|display|creator|pocket|selfie)/.test(t)) return 'Creator & Productivity Tech';
 if (/(ring|glasses|wearable|pendant|exoskeleton|buds)/.test(t)) return 'Future Gadgets';
 if (/(tire|car|road|luggage|bike|mobility|power bank)/.test(t)) return 'Mobility / Outdoor / Emergency';
 return 'Future Gadgets';
}
return $input.all().map(i => {
 const j = i.json;
 const hasLink = !!j.buy_url;
 const score = 50 + (hasLink ? 20 : 0) + (j.product_name.length > 8 ? 10 : 0);
 return { json: { ...j, category: category(j.product_name), trend_score: Math.min(score, 95), verification_status: hasLink ? 'Researching' : 'Needs Link', monetization: hasLink ? 'affiliate_candidate' : 'research_candidate' } };
});
